  string user_id = 1;
  optional string nickname         = 2;
  optional string introduction     = 3;
  optional string birth_date       = 4;
  optional Gender gender           = 5;
  optional string region_code      = 6;
  repeated string interest_codes   = 7;
  repeated string profile_image_ids = 8;
  optional string voice_sample_id  = 9;
  optional int32  height           = 10;
  optional string job_code         = 11;
  optional string purpose_code     = 12;
